import{c as s,cN as t,cG as i,cb as a,c8 as e,cf as l,cT as n,cg as r,d,ce as h}from"./chunks/framework.BlkIsu1j.js";const o=JSON.parse('{"title":"工作原理","description":"","frontmatter":{"title":"工作原理","outline":"deep","layout":"doc","prev":"/ai/claudecode/01-installation","next":"/ai/claudecode/03-core-features","date":"2026-05-20T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecode/02-how-it-works.md","filePath":"ai/claudecode/02-how-it-works.md","lastUpdated":1780060624000}'),p={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"ai/claudecode/02-how-it-works.md"},[["render",function(s,o,k,g,c,u){const E=t("vitepress-mermaid");return i(),a("div",null,[e("h1",p,[l(n(s.$frontmatter.title)+" ",1),o[0]||(o[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),o[1]||(o[1]=e("p",null,"理解 Claude Code 的底层机制，能帮助你更高效地使用它、减少意料之外的行为、写出更好的提示。",-1)),o[2]||(o[2]=e("h2",{id:"agent-loop-核心运转模型",tabindex:"-1"},[l("Agent Loop：核心运转模型 "),e("a",{class:"header-anchor",href:"#agent-loop-核心运转模型","aria-label":"Permalink to “Agent Loop：核心运转模型”"},"​")],-1)),o[3]||(o[3]=e("p",null,[l("Claude Code 的一切行为都围绕 "),e("strong",null,"Agent Loop"),l("（代理循环）展开：")],-1)),r(E,{value:'flowchart TB\n    A["理解意图"] --\x3e B["制定计划"]\n    B --\x3e C["调用工具"]\n    C --\x3e D{"观察结果"}\n    D --\x3e|"未完成"| B\n    D --\x3e|"完成 / 需输入 / 达上限"| END["退出循环"]\n\n    style A fill:#e1f5fe\n    style B fill:#e8f5e9\n    style C fill:#fff3e0\n    style D fill:#f3e5f5\n    style END fill:#ffebee'}),o[4]||(o[4]=e("p",null,[e("img",{src:d,alt:"Agentic Loop",loading:"lazy"})],-1)),r(E,{value:'flowchart LR\n    P["你的提示"]\n\n    subgraph Loop["agentic loop"]\n        direction LR\n        GC["收集上下文"] --\x3e TA["执行操作"] --\x3e VR["验证结果"]\n        VR -."循环".-> GC\n    end\n\n    D["完成"]\n    H["你：中断、引导<br>或补充上下文"]\n\n    P --\x3e GC\n    VR --\x3e D\n    H -."介入".-> TA\n\n    style P fill:#e8e8e4,stroke:#999\n    style D fill:#e8e8e4,stroke:#999\n    style GC fill:#d4e4d8,stroke:#8ab\n    style TA fill:#d4e4d8,stroke:#8ab\n    style VR fill:#d4e4d8,stroke:#8ab\n    style H fill:#fdf6f2,stroke:#d4a27f'}),o[5]||(o[5]=h('<p>每一轮对话中，Claude Code 会：</p><ol><li><strong>理解意图</strong>：解析你的消息，结合当前项目上下文</li><li><strong>制定计划</strong>：决定用什么工具、按什么顺序执行</li><li><strong>调用工具</strong>：执行 Read / Write / Edit / Bash / Agent 等操作</li><li><strong>观察结果</strong>：读取工具返回的结果，判断是否达到目标</li><li><strong>迭代</strong>：如果结果不理想或需要更多操作，回到步骤 2</li></ol><p>这个循环是 <strong>自主进行</strong> 的——你只需要在关键节点（权限确认、结果审查）介入。</p><h2 id="工具系统" tabindex="-1">工具系统 <a class="header-anchor" href="#工具系统" aria-label="Permalink to “工具系统”">​</a></h2><p>Claude Code 拥有一套完整的工具来操作你的项目。以下是核心工具及其用途：</p><h3 id="文件工具" tabindex="-1">文件工具 <a class="header-anchor" href="#文件工具" aria-label="Permalink to “文件工具”">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>作用</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>Read</strong></td><td>读取文件内容</td><td>理解现有代码、查看配置文件</td></tr><tr><td><strong>Write</strong></td><td>创建或覆写文件</td><td>新建文件、完全重写</td></tr><tr><td><strong>Edit</strong></td><td>精准文本替换</td><td>修改文件中特定位置</td></tr><tr><td><strong>Bash</strong></td><td>执行 Shell 命令</td><td>运行构建、测试、Git 操作</td></tr></tbody></table><h3 id="高级工具" tabindex="-1">高级工具 <a class="header-anchor" href="#高级工具" aria-label="Permalink to “高级工具”">​</a></h3><table tabindex="0"><thead><tr><th>工具</th><th>作用</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td>启动子代理</td><td>并行执行独立任务</td></tr><tr><td><strong>WebFetch</strong></td><td>抓取网页内容</td><td>查阅在线文档</td></tr><tr><td><strong>WebSearch</strong></td><td>搜索网络</td><td>获取最新信息</td></tr><tr><td><strong>TodoWrite</strong></td><td>管理任务列表</td><td>跟踪复杂任务进度</td></tr><tr><td><strong>TaskOutput</strong></td><td>获取后台任务结果</td><td>查询异步任务状态</td></tr></tbody></table><h3 id="工具调用机制" tabindex="-1">工具调用机制 <a class="header-anchor" href="#工具调用机制" aria-label="Permalink to “工具调用机制”">​</a></h3><p>每次 Claude Code 决定使用工具时，会经历以下流程：</p><ol><li>模型输出工具调用请求（JSON 格式）</li><li>CLI/IDE 层解析请求，在本机执行</li><li>执行结果返回给模型</li><li>模型分析结果，决定下一步</li></ol><p>对于 <strong>高风险操作</strong>（如 Bash 中的 <code>rm -rf</code>、Git push --force 等），系统会先弹出权限确认弹窗，由你决定是否允许。</p><h2 id="上下文管理" tabindex="-1">上下文管理 <a class="header-anchor" href="#上下文管理" aria-label="Permalink to “上下文管理”">​</a></h2><p>Claude Code 的智能很大程度上来自它的上下文管理系统。每次对话，它都能访问：</p><h3 id="_1-system-prompt-系统提示词" tabindex="-1">1. System Prompt（系统提示词） <a class="header-anchor" href="#_1-system-prompt-系统提示词" aria-label="Permalink to “1. System Prompt（系统提示词）”">​</a></h3><p>每次对话都附带一个预置的系统提示词，它定义了 Claude Code 的：</p><ul><li>行为准则（安全性、编码风格）</li><li>工具使用说明</li><li>当前平台信息（操作系统、Shell 类型）</li><li>Git 状态快照</li></ul><p>你无法修改系统提示词，但可以通过 <code>CLAUDE.md</code> 追加指令。</p><h3 id="_2-claude-md-项目上下文" tabindex="-1">2. CLAUDE.md（项目上下文） <a class="header-anchor" href="#_2-claude-md-项目上下文" aria-label="Permalink to “2. CLAUDE.md（项目上下文）”">​</a></h3><p>项目根目录下的 <code>CLAUDE.md</code> 文件是 <strong>最重要的上下文来源</strong>。它在每次对话启动时被自动读取，内容可以包括：</p><ul><li>项目架构说明</li><li>常用命令</li><li>编码规范</li><li>特定约定和注意事项</li></ul><div class="language-markdown"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># CLAUDE.md</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Commands</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> `pnpm dev`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — 启动开发服务器</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> `pnpm test`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — 运行测试</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Architecture</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> `src/`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — 前端源码</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> `api/`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — 后端 API</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 使用 React + TypeScript + Tailwind</span></span></code></pre></div><h3 id="_3-memory-持久化记忆" tabindex="-1">3. Memory（持久化记忆） <a class="header-anchor" href="#_3-memory-持久化记忆" aria-label="Permalink to “3. Memory（持久化记忆）”">​</a></h3><p>Memory 系统会在项目目录 <code>.claude/projects/&lt;path&gt;/memory/</code> 下存储持久化信息：</p><ul><li><strong>用户角色</strong>：你的技术背景、偏好</li><li><strong>项目上下文</strong>：当前目标、已知问题</li><li><strong>反馈记录</strong>：你之前的纠正和确认</li></ul><p>这种记忆是<strong>跨会话</strong>的——下次打开 Claude Code 时，它会记得之前的约定。</p><h3 id="_4-对话上下文窗口" tabindex="-1">4. 对话上下文窗口 <a class="header-anchor" href="#_4-对话上下文窗口" aria-label="Permalink to “4. 对话上下文窗口”">​</a></h3><p>每个模型都有<strong>上下文窗口限制</strong>：</p><table tabindex="0"><thead><tr><th>模型</th><th>上下文窗口</th></tr></thead><tbody><tr><td>Opus 4.7</td><td>200K tokens</td></tr><tr><td>Sonnet 4.6</td><td>200K tokens</td></tr><tr><td>Haiku 4.5</td><td>200K tokens</td></tr></tbody></table><p>当对话接近窗口上限时，Claude Code 会自动<strong>压缩</strong>（compact）历史消息，保留关键信息，释放空间。你也可以手动执行 <code>/compact</code> 命令。</p><h2 id="权限模型" tabindex="-1">权限模型 <a class="header-anchor" href="#权限模型" aria-label="Permalink to “权限模型”">​</a></h2><p>Claude Code 的权限系统分为三个层级：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Level 1: 自动允许 — 读文件、搜索代码（无副作用）</span></span>\n<span class="line"><span>Level 2: 按需确认 — 写文件、执行测试命令</span></span>\n<span class="line"><span>Level 3: 始终确认 — rm、sudo、force push（高风险）</span></span></code></pre></div><p>你可以在 <code>settings.json</code> 中自定义权限规则：</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;permissions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;allow&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(npm:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(git:status)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(git:diff)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;deny&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(rm:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(sudo:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bash(curl:*)&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="安全沙箱" tabindex="-1">安全沙箱 <a class="header-anchor" href="#安全沙箱" aria-label="Permalink to “安全沙箱”">​</a></h3><p>Claude Code 默认运行在一个受限环境中：</p><ul><li><strong>文件访问</strong>：限制在项目目录内</li><li><strong>网络请求</strong>：需要通过 WebFetch/WebSearch 工具（可审核）</li><li><strong>Shell 命令</strong>：在子进程中执行，不影响主 Shell 状态</li><li><strong>环境变量</strong>：不会自动读取 <code>.env</code> 等敏感文件</li></ul><h2 id="模型选择与-thinking-机制" tabindex="-1">模型选择与 Thinking 机制 <a class="header-anchor" href="#模型选择与-thinking-机制" aria-label="Permalink to “模型选择与 Thinking 机制”">​</a></h2><h3 id="可用模型" tabindex="-1">可用模型 <a class="header-anchor" href="#可用模型" aria-label="Permalink to “可用模型”">​</a></h3><p>Claude Code 使用 Claude 4 系列模型：</p><ul><li><strong>Opus 4.7</strong>：最强推理能力，适合复杂重构和架构设计</li><li><strong>Sonnet 4.6</strong>：平衡性能与速度，日常开发首选</li><li><strong>Haiku 4.5</strong>：最快响应，适合轻量任务</li></ul><h3 id="thinking-模式" tabindex="-1">Thinking 模式 <a class="header-anchor" href="#thinking-模式" aria-label="Permalink to “Thinking 模式”">​</a></h3><p>Claude Code 支持 <strong>Extended Thinking</strong>（深度思考模式），模型在进行复杂操作前会进行额外的推理：</p><ul><li>默认自动激活，当任务需要深度分析时</li><li>你可以在指令中明确要求：&quot;用 thinking 模式分析这个架构&quot;</li><li>思考过程不占用输出 token</li></ul><h3 id="fast-mode" tabindex="-1">Fast Mode <a class="header-anchor" href="#fast-mode" aria-label="Permalink to “Fast Mode”">​</a></h3><p>VSCode 扩展支持 Fast Mode——在 Opus 模型上获得更快的输出速度，适合需要 Opus 推理能力又不想等待的场景。通过 <code>/fast</code> 命令切换。</p><h2 id="关键设计原则" tabindex="-1">关键设计原则 <a class="header-anchor" href="#关键设计原则" aria-label="Permalink to “关键设计原则”">​</a></h2><p>了解 Claude Code 的几条设计原则，有助于预测它的行为：</p><ol><li><strong>宁可不做也不错做</strong>：对于高风险操作，默认需要确认</li><li><strong>上下文优先</strong>：先读文件理解，再动手修改</li><li><strong>渐进式变更</strong>：倾向于小步迭代而非一次性大改</li><li><strong>可逆性考量</strong>：优先选择可撤销的操作路径</li><li><strong>透明化</strong>：所有工具调用和结果对你可见</li></ol>',51))])}]]);export{o as __pageData,k as default};
